fn main() -> i64 = {
    let capacity = read_int();
    let n = read_int();

    // Pre-allocate buffer with zeros
    let buf = vec_new();
    let mut i = 0;
    while i < capacity {
        let _p = vec_push(buf, 0);
        i = i + 1
    };

    let mut head = 0;
    let mut tail = 0;
    let mut count = 0;

    let mut op_idx = 0;
    while op_idx < n {
        let op = read_int();

        if op == 1 {
            let val = read_int();
            if count == capacity {
                // Full: overwrite oldest, advance head
                let _w = vec_set(buf, tail, val);
                tail = (tail + 1) % capacity;
                head = (head + 1) % capacity;
            } else {
                // Not full: insert at tail
                let _w = vec_set(buf, tail, val);
                tail = (tail + 1) % capacity;
                count = count + 1
            }
        } else if op == 2 {
            // Read (dequeue oldest)
            if count > 0 {
                let oldest = vec_get(buf, head);
                head = (head + 1) % capacity;
                count = count - 1;
                let _p = println(oldest);
            } else {
                let _p = println(-1);
            }
        } else if op == 3 {
            // Size
            let _p = println(count);
        }

        op_idx = op_idx + 1
    };

    let _f = vec_free(buf);
    0
};

